// Pipeline Monitor v1 — checks health of the entire content pipeline
// Generates alerts for: stalled pipeline, low volume, unpublished clusters, high error rate

const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };

async function query(table, params) {
  const qs = Object.entries(params).map(([k,v]) => k + '=' + encodeURIComponent(v)).join('&');
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/' + table + '?' + qs,
      headers: headers,
      json: true
    });
    return Array.isArray(resp) ? resp : [];
  } catch (e) { return []; }
}

const now = new Date();
const h6ago = new Date(now.getTime() - 6 * 60 * 60 * 1000).toISOString();
const h24ago = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
const h48ago = new Date(now.getTime() - 48 * 60 * 60 * 1000).toISOString();

// 1. Check staging volume (last 6h)
const recentStaging = await query.call(this, 'news_staging', {
  select: 'id', 'collected_at': 'gte.' + h6ago
});

// 2. Check unprocessed staging (stale items)
const unprocessed = await query.call(this, 'news_staging', {
  select: 'id,collected_at', processed: 'eq.false', 'collected_at': 'lte.' + h6ago, limit: '50'
});

// 3. Check clusters without published posts (last 48h)
const recentClusters = await query.call(this, 'news_clusters', {
  select: 'id,fingerprint,topic,confidence_score', 'created_at': 'gte.' + h48ago, 'confidence_score': 'gte.60'
});
const curatedPosts = await query.call(this, 'curated_posts', {
  select: 'cluster_id,status', 'created_at': 'gte.' + h48ago
});
const publishedClusterIds = new Set(curatedPosts.filter(p => ['ready','published','human-reviewed'].includes(p.status)).map(p => p.cluster_id));
const unpublishedClusters = recentClusters.filter(c => !publishedClusterIds.has(c.id));

// 4. Check error rate in recent automations
const recentExecutions = await query.call(this, 'automation_executions', {
  select: 'status', 'started_at': 'gte.' + h24ago
});
const errorExecs = recentExecutions.filter(e => e.status === 'error' || e.status === 'failed');
const errorRate = recentExecutions.length > 0 ? (errorExecs.length / recentExecutions.length * 100) : 0;

// 5. Check curated posts pending review for too long (> 24h)
const stalePending = await query.call(this, 'curated_posts', {
  select: 'id,title,status,created_at', status: 'in.(pending-review,auto-draft)', 'created_at': 'lte.' + h24ago, limit: '20'
});


// 6. Auto-cleanup: delete auto-draft curated posts older than 8 hours
const h8ago = new Date(now.getTime() - 8 * 60 * 60 * 1000).toISOString();
let cleanupCount = 0;
try {
  const staleAutoDrafts = await query.call(this, 'curated_posts', {
    select: 'id,title', status: 'eq.auto-draft', 'created_at': 'lte.' + h8ago, limit: '50'
  });
  if (staleAutoDrafts.length > 0) {
    const ids = staleAutoDrafts.map(p => p.id);
    // Delete via Supabase REST API with filter
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: SUPABASE_URL + '/rest/v1/curated_posts?id=in.(' + ids.join(',') + ')&status=eq.auto-draft',
      headers: { ...headers, 'Prefer': 'return=minimal' },
    });
    cleanupCount = staleAutoDrafts.length;
  }
} catch (e) {
  // Non-fatal: log and continue
}

// Generate alerts
const alerts = [];

// Pipeline stalled: no new staging in 6h
if (recentStaging.length === 0) {
  alerts.push({
    alert_type: 'pipeline_stalled',
    severity: 'critical',
    title: 'Pipeline de coleta parado',
    detail: 'Nenhum item coletado nas ultimas 6 horas. Verificar WF-01 e feeds RSS.',
    metadata: { hours_since_last: 6, check_time: now.toISOString() }
  });
}

// Low volume: < 5 items in 6h
if (recentStaging.length > 0 && recentStaging.length < 5) {
  alerts.push({
    alert_type: 'low_volume',
    severity: 'warning',
    title: 'Volume baixo de coleta',
    detail: 'Apenas ' + recentStaging.length + ' itens coletados nas ultimas 6h. Normal e > 10.',
    metadata: { count_6h: recentStaging.length }
  });
}

// Stale unprocessed items
if (unprocessed.length > 10) {
  alerts.push({
    alert_type: 'pipeline_stalled',
    severity: 'warning',
    title: 'Itens acumulados sem processar',
    detail: unprocessed.length + ' itens no staging ha mais de 6h sem processamento. Verificar WF-02.',
    metadata: { unprocessed_count: unprocessed.length }
  });
}

// Unpublished high-confidence clusters
if (unpublishedClusters.length > 3) {
  alerts.push({
    alert_type: 'unpublished_clusters',
    severity: 'warning',
    title: 'Clusters sem publicacao',
    detail: unpublishedClusters.length + ' clusters com confianca >= 60 sem post curado nas ultimas 48h.',
    metadata: { cluster_count: unpublishedClusters.length, topics: unpublishedClusters.map(c => c.topic).filter(Boolean) }
  });
}

// High error rate
if (errorRate > 30 && recentExecutions.length >= 3) {
  alerts.push({
    alert_type: 'high_error_rate',
    severity: 'critical',
    title: 'Taxa de erro alta nas automacoes',
    detail: Math.round(errorRate) + '% de erro (' + errorExecs.length + '/' + recentExecutions.length + ') nas ultimas 24h.',
    metadata: { error_rate: Math.round(errorRate), total: recentExecutions.length, errors: errorExecs.length }
  });
}

// Stale pending reviews
if (stalePending.length > 0) {
  alerts.push({
    alert_type: 'stale_reviews',
    severity: 'info',
    title: 'Posts aguardando revisao ha mais de 24h',
    detail: stalePending.length + ' posts em pending-review ou auto-draft ha mais de 24h.',
    metadata: { count: stalePending.length, titles: stalePending.slice(0, 5).map(p => p.title) }
  });
}

// Auto-draft cleanup alert
if (cleanupCount > 0) {
  alerts.push({
    alert_type: 'auto_cleanup',
    severity: 'info',
    title: 'Auto-draft cleanup executado',
    detail: cleanupCount + ' posts auto-draft com mais de 8h removidos automaticamente.',
    metadata: { cleaned: cleanupCount }
  });
}

// Build summary
const summary = {
  check_time: now.toISOString(),
  staging_6h: recentStaging.length,
  unprocessed_stale: unprocessed.length,
  clusters_48h: recentClusters.length,
  unpublished_clusters: unpublishedClusters.length,
  error_rate_24h: Math.round(errorRate),
  pending_reviews: stalePending.length,
  auto_drafts_cleaned: cleanupCount,
  alerts_generated: alerts.length,
  health_status: alerts.some(a => a.severity === 'critical') ? 'critical' : alerts.some(a => a.severity === 'warning') ? 'degraded' : 'healthy'
};

return [{ json: { summary: summary, alerts: alerts } }];

const data = $json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };

// Save alerts to pipeline_alerts table
for (const alert of data.alerts) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/pipeline_alerts',
      headers: headers,
      body: alert,
      json: true
    });
  } catch (e) { /* continue on fail */ }
}

// Send notification email for critical alerts
const criticalAlerts = data.alerts.filter(a => a.severity === 'critical');
if (criticalAlerts.length > 0) {
  const alertText = criticalAlerts.map(a => '⚠️ ' + a.title + '\n' + a.detail).join('\n\n');
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/functions/v1/send-email',
      headers: { ...headers, 'Authorization': 'Bearer ' + SUPABASE_KEY },
      body: {
        to: $env.ADMIN_EMAIL || 'admin@vision7.pt',
        subject: '[Vision7] ALERTA Pipeline: ' + data.summary.health_status.toUpperCase(),
        html: '<h2>Alertas do Pipeline Vision7</h2><p>Status: <strong>' + data.summary.health_status + '</strong></p><pre>' + alertText + '</pre><hr><p>Verificacao automatica em ' + data.summary.check_time + '</p>'
      },
      json: true
    });
  } catch (e) { /* email send failed, alert is still saved in DB */ }
}

return [{ json: { saved_alerts: data.alerts.length, critical_notified: criticalAlerts.length, summary: data.summary } }];

// Update health summary in automations_v2 config or log
const data = $json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// Log the healthy state
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/pipeline_alerts',
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' },
    body: {
      alert_type: 'health_check_ok',
      severity: 'info',
      title: 'Pipeline saudavel',
      detail: 'Verificacao completa sem alertas. Staging 6h: ' + data.summary.staging_6h + ', Clusters 48h: ' + data.summary.clusters_48h,
      metadata: data.summary,
      resolved: true,
      resolved_at: new Date().toISOString()
    },
    json: true
  });
} catch (e) { /* ok */ }

return [{ json: { status: 'healthy', summary: data.summary } }];
